import{_ as t,o as a,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"59. Continuing Medical Education Leave","description":"","frontmatter":{"title":"59. Continuing Medical Education Leave","eba":"Medical Specialists 2022-2026","topics":["leave","employment","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/59-continuing-medical-education-leave.md","filePath":"ebas/medical-specialists/leave/59-continuing-medical-education-leave.md"}'),o={name:"ebas/medical-specialists/leave/59-continuing-medical-education-leave.md"};function r(c,e,l,s,d,p){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_59-continuing-medical-education-leave" tabindex="-1">59. Continuing Medical Education Leave <a class="header-anchor" href="#_59-continuing-medical-education-leave" aria-label="Permalink to &quot;59. Continuing Medical Education Leave&quot;">​</a></h1><p><strong>59.1</strong> Eligibility</p><p>Continuing Medical Education (CME) Leave is available to Full-Time and Fractional Doctors.</p><p><strong>59.2</strong> Leave entitlement:</p><p>Doctors are entitled to 2 weeks leave (pro rata for Fractional Doctors) for relevant CME Leave each year on full pay unless the Chief Medical Officer/delegate approves a greater entitlement in writing. Such entitlement shall accumulate to a maximum of two years of entitlement (4 weeks, pro rata) unless otherwise approved in writing by the Health Service’s Chief Medical Officer/delegate.</p><p><strong>(a)</strong> For the purposes of this clause, a “week” is defined as the normal hours/days worked by the Doctor consistent with this Agreement or Contract or Letter of Appointment.</p><p><strong>(b)</strong> This entitlement to CME Leave wholly replaces any previous entitlement to Conference Leave or any other paid study or CME Leave (other than Sabbatical Leave or CME Leave accrued under the 2018 ) provided.</p><p><strong>(c)</strong> The payment entitlement for CME Leave for Doctors employed on a Fractional basis will be in accordance with their Fractional allocation.</p><p><strong>59.3</strong> Applying for and Granting of Leave:</p><p><strong>(a)</strong> Subject to agreement otherwise, applications for leave will be made at least four weeks in advance in writing to the Chief Medical Officer or Delegate.</p><p><strong>(b)</strong> Approval will not be unreasonably withheld.</p><p><strong>(c)</strong> The Doctor may be required to report to the Health Service’s executive and/or to the medical cohort on the knowledge or skills acquired by undertaking the approved CME activity.</p><p><strong>59.4</strong> Clinical Academics</p><p><strong>(a)</strong> For the avoidance of doubt, the attendance of a Clinical Academic at a conference to deliver medical education is not a CME activity and no deduction from the leave entitlements under this clause shall occur in those circumstances.</p><p><strong>(b)</strong> The approval and attendance of a Clinical Academic at a conference to deliver medical education in paid time shall be agreed between the Clinical Academic, Health Service and relevant University unless it is a requirement of the University to attend.</p>',15)])])}const m=t(o,[["render",r]]);export{h as __pageData,m as default};
